import{_ as s,o as i,c as e,a2 as t}from"./chunks/framework.CIFdlppq.js";const g=JSON.parse('{"title":"日志排查手册","description":"","frontmatter":{},"headers":[],"relativePath":"faq/troubleshooting.md","filePath":"faq/troubleshooting.md","lastUpdated":1782678748000}'),l={name:"faq/troubleshooting.md"};function n(r,a,h,o,p,d){return i(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="日志排查手册" tabindex="-1">日志排查手册 <a class="header-anchor" href="#日志排查手册" aria-label="Permalink to &quot;日志排查手册&quot;">​</a></h1><p>常见错误代码与解决方案速查。</p><h2 id="启动类错误" tabindex="-1">启动类错误 <a class="header-anchor" href="#启动类错误" aria-label="Permalink to &quot;启动类错误&quot;">​</a></h2><h3 id="eaddrinuse-端口已占用" tabindex="-1">EADDRINUSE - 端口已占用 <a class="header-anchor" href="#eaddrinuse-端口已占用" aria-label="Permalink to &quot;EADDRINUSE - 端口已占用&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Error: listen EADDRINUSE: address already in use :::3456</span></span></code></pre></div><p><strong>原因</strong>：3456 端口被其他进程占用。</p><p><strong>解决</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查找占用进程</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">netstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ano</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> findstr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3456</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 更换端口启动</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ai-verify-mcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --http</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3457</span></span></code></pre></div><h3 id="playwright-浏览器不可用" tabindex="-1">Playwright 浏览器不可用 <a class="header-anchor" href="#playwright-浏览器不可用" aria-label="Permalink to &quot;Playwright 浏览器不可用&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Error: Playwright browser is not available</span></span></code></pre></div><p><strong>原因</strong>：Chromium 浏览器未安装。</p><p><strong>解决</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chromium</span></span></code></pre></div><h2 id="网络类错误" tabindex="-1">网络类错误 <a class="header-anchor" href="#网络类错误" aria-label="Permalink to &quot;网络类错误&quot;">​</a></h2><h3 id="页面加载超时" tabindex="-1">页面加载超时 <a class="header-anchor" href="#页面加载超时" aria-label="Permalink to &quot;页面加载超时&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Timeout 30000ms exceeded.</span></span></code></pre></div><p><strong>原因</strong>：页面加载太慢或网络不通。</p><p><strong>排查</strong>：</p><ol><li>确认目标 URL 从当前网络可达</li><li>检查是否需要代理</li><li>增加超时时间</li><li>检查目标服务是否正常启动</li></ol><h3 id="cors-跨域错误" tabindex="-1">CORS 跨域错误 <a class="header-anchor" href="#cors-跨域错误" aria-label="Permalink to &quot;CORS 跨域错误&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Access to fetch at &#39;...&#39; has been blocked by CORS policy</span></span></code></pre></div><p><strong>原因</strong>：后端接口未配置跨域。</p><p><strong>解决</strong>：</p><ul><li>后端添加 CORS 头</li><li>或使用浏览器的禁用安全模式（仅本地测试用）</li></ul><h3 id="ssl-证书错误" tabindex="-1">SSL 证书错误 <a class="header-anchor" href="#ssl-证书错误" aria-label="Permalink to &quot;SSL 证书错误&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>net::ERR_CERT_AUTHORITY_INVALID</span></span></code></pre></div><p><strong>原因</strong>：自签名证书或证书过期。</p><p><strong>解决</strong>：配置忽略证书错误（仅测试环境）。</p><h2 id="工具调用类错误" tabindex="-1">工具调用类错误 <a class="header-anchor" href="#工具调用类错误" aria-label="Permalink to &quot;工具调用类错误&quot;">​</a></h2><h3 id="选择器找不到元素" tabindex="-1">选择器找不到元素 <a class="header-anchor" href="#选择器找不到元素" aria-label="Permalink to &quot;选择器找不到元素&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Error: No node found for selector: ...</span></span></code></pre></div><p><strong>排查步骤</strong>：</p><ol><li>确认选择器拼写正确</li><li>页面是否加载完成</li><li>元素是否在 iframe 中</li><li>元素是否被动态渲染</li><li>用 <code>browser_find_element</code> 智能查找</li></ol><h3 id="工具列表为空" tabindex="-1">工具列表为空 <a class="header-anchor" href="#工具列表为空" aria-label="Permalink to &quot;工具列表为空&quot;">​</a></h3><p><strong>原因</strong>：MCP Server 未正确连接。</p><p><strong>排查</strong>：</p><ol><li>重启 AI 客户端会话</li><li>检查配置文件 JSON 格式</li><li>检查命令路径是否正确</li><li>手动运行命令测试：<code>npx ai-verify-mcp health</code></li></ol><h3 id="trae-40-工具上限" tabindex="-1">Trae 40 工具上限 <a class="header-anchor" href="#trae-40-工具上限" aria-label="Permalink to &quot;Trae 40 工具上限&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>list tools failed</span></span></code></pre></div><p><strong>原因</strong>：Trae 单个 Server 工具上限 40 个，本项目有 76 个。</p><p><strong>解决</strong>：减少其他 MCP Server，只保留需要的。</p><h2 id="产物类错误" tabindex="-1">产物类错误 <a class="header-anchor" href="#产物类错误" aria-label="Permalink to &quot;产物类错误&quot;">​</a></h2><h3 id="截图不生成" tabindex="-1">截图不生成 <a class="header-anchor" href="#截图不生成" aria-label="Permalink to &quot;截图不生成&quot;">​</a></h3><p><strong>排查</strong>：</p><ol><li>检查 <code>VALIDPILOT_ARTIFACTS_DIR</code> 目录权限</li><li>确认磁盘空间充足</li><li>查看 Console 错误</li></ol><h3 id="产物目录找不到" tabindex="-1">产物目录找不到 <a class="header-anchor" href="#产物目录找不到" aria-label="Permalink to &quot;产物目录找不到&quot;">​</a></h3><p>默认产物目录是 <code>./artifacts/</code>（相对于当前工作目录）。</p><p>设置自定义路径：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> VALIDPILOT_ARTIFACTS_DIR=E:/my-reports</span></span></code></pre></div><h2 id="配置类错误" tabindex="-1">配置类错误 <a class="header-anchor" href="#配置类错误" aria-label="Permalink to &quot;配置类错误&quot;">​</a></h2><h3 id="环境变量不生效" tabindex="-1">环境变量不生效 <a class="header-anchor" href="#环境变量不生效" aria-label="Permalink to &quot;环境变量不生效&quot;">​</a></h3><p><strong>排查</strong>：</p><ol><li>确认 <code>.env</code> 文件在项目根目录</li><li>变量名拼写正确</li><li>布尔值用 <code>true</code>/<code>false</code></li><li>重启 Server 使配置生效</li></ol><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><h3 id="开启调试日志" tabindex="-1">开启调试日志 <a class="header-anchor" href="#开启调试日志" aria-label="Permalink to &quot;开启调试日志&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NODE_ENV=development</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ai-verify-mcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><h3 id="可视化调试" tabindex="-1">可视化调试 <a class="header-anchor" href="#可视化调试" aria-label="Permalink to &quot;可视化调试&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> BROWSER_HEADLESS=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ai-verify-mcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> validate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:5173</span></span></code></pre></div><p>可以看到浏览器实际操作过程。</p><h3 id="查看-har-记录" tabindex="-1">查看 HAR 记录 <a class="header-anchor" href="#查看-har-记录" aria-label="Permalink to &quot;查看 HAR 记录&quot;">​</a></h3><p>用 <code>browser_har_export</code> 导出 HAR 文件，在 Chrome DevTools 中分析网络请求。</p><h3 id="playwright-trace" tabindex="-1">Playwright Trace <a class="header-anchor" href="#playwright-trace" aria-label="Permalink to &quot;Playwright Trace&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>browser_trace_start</span></span>
<span class="line"><span>... 操作 ...</span></span>
<span class="line"><span>browser_trace_stop</span></span></code></pre></div><p>生成 trace.zip，在 <a href="https://trace.playwright.dev/" target="_blank" rel="noreferrer">https://trace.playwright.dev/</a> 中回放。</p><hr><h2 id="获取帮助" tabindex="-1">获取帮助 <a class="header-anchor" href="#获取帮助" aria-label="Permalink to &quot;获取帮助&quot;">​</a></h2><ul><li>GitHub Issues: <a href="https://github.com/validpilot/ai-verify-mcp/issues" target="_blank" rel="noreferrer">https://github.com/validpilot/ai-verify-mcp/issues</a></li><li>邮箱: <a href="mailto:validpilot@outlook.com" target="_blank" rel="noreferrer">validpilot@outlook.com</a></li><li>钉钉交流群：见 README</li></ul>`,67)])])}const k=s(l,[["render",n]]);export{g as __pageData,k as default};
